async (params, browser) => {
  // Open ESPN standings
  await browser.open(`https://www.espn.com/${params.sport}/standings`)

  // Wait for standings table
  await browser.waitForSelector('table, [class*=\'standings\'], .content', 15000)

  // Let standings render
  await browser.wait(3000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract standings
  const result = await browser.evaluate(`const headers = []; document.querySelectorAll('table thead th, table thead td, [class*="Table__TH"]').forEach(th => { const text = th.textContent?.trim(); if (text) headers.push(text); }); const teams = []; document.querySelectorAll('table tbody tr, [class*="standings"] tbody tr').forEach((el, i) => { if (i < 40) { const nameEl = el.querySelector('a[href*="/team/"], .team-link, [class*="TeamLink"], td:first-child a'); const cells = el.querySelectorAll('td'); const stats = []; cells.forEach((c, ci) => { if (ci > 0) stats.push(c.textContent?.trim()); }); if (nameEl?.textContent?.trim()) { teams.push({ team: nameEl.textContent.trim(), url: nameEl.href || '', stats: stats }); } } }); return { sport: params.sport, headers: headers, team_count: teams.length, teams: teams };`)

  return result
}
